INSERT INTO ebooks (id, title, author, r2_key, category_id, license_status, license_note) VALUES (400, 'Episode 1: Luqman Dianugerahi Hikmah dan Perintah Bersyukur', 'Tim Editorial ULYAH', 'ebooks/kisah-luqman/id/kisah-luqman-01-hikmah-dan-syukur.pdf', 5, 'original', 'Ditulis berdasarkan QS. Luqman 12-12 (quran-json, CC-BY-4.0). Tidak ada kutipan pihak ketiga berhak cipta.');
INSERT INTO stories (title, slug, lang, series_key, episode_number, category_id, body, ai_generated, qc_status, source_format, status, confidence_score, related_ayah_id, pdf_ebook_id, published_at)
SELECT 'Episode 1: Luqman Dianugerahi Hikmah dan Perintah Bersyukur', 'kisah-luqman-01-hikmah-dan-syukur', 'id', 'kisah-luqman', 1, 5, 'Luqman Al-Hakim adalah seorang hamba saleh yang namanya diabadikan sebagai judul sebuah surah dalam Al-Qur''an. Allah menganugerahinya "hikmah" — kebijaksanaan, pemahaman yang lurus, dan ketepatan dalam berkata serta bertindak. Allah berfirman, "Dan sungguh, telah Kami berikan hikmah kepada Luqman, yaitu, ‘Bersyukurlah kepada Allah! Dan barangsiapa bersyukur (kepada Allah), maka sesungguhnya dia bersyukur untuk dirinya sendiri; dan barangsiapa tidak bersyukur (kufur), maka sesungguhnya Allah Mahakaya, Maha Terpuji’" (QS. Luqman: 12).

Perhatikan bahwa inti pertama dari hikmah yang Allah sebutkan adalah perintah bersyukur. Ini menunjukkan bahwa puncak kebijaksanaan bukanlah kepandaian berdebat, melainkan kesadaran mengenal nikmat Allah dan mensyukurinya. Orang yang bijak adalah orang yang tahu berterima kasih kepada Pemberi nikmat.

Ayat ini juga mengajarkan bahwa manfaat syukur kembali kepada pelakunya sendiri: "dia bersyukur untuk dirinya sendiri". Allah tidak butuh syukur hamba; Dialah Yang Mahakaya lagi Maha Terpuji. Syukurlah yang menambah nikmat, sedangkan kufur nikmat hanya merugikan diri.

Hikmah: kebijaksanaan sejati bermula dari hati yang bersyukur. Sebelum Luqman menasihati anaknya tentang banyak hal, Allah lebih dahulu mengajarkan bahwa dasar semua kebaikan adalah mengenal dan mensyukuri Sang Pemberi.

Sumber & Catatan: dalil dari Al-Qur''an, QS. Luqman: 12 (teks & terjemahan dari dataset quran-json). Jumhur (mayoritas) ulama berpendapat Luqman adalah seorang hamba saleh yang bijak, bukan seorang nabi. Keterangan tentang asal-usulnya (sebagian riwayat menyebut ia dari Habasyah/Nubia) bersumber dari tradisi/tafsir dan tidak dipastikan; yang tegas dari ayat adalah bahwa ia diberi hikmah.', 0, 'qc_pending', 'ai_original', 'published', 1.0,
  (SELECT id FROM ayah WHERE surah_id = 31 AND number = 12), 400, datetime('now');
INSERT INTO ebooks (id, title, author, r2_key, category_id, license_status, license_note) VALUES (401, 'Episode 1: Luqman Is Granted Wisdom and Commanded to Give Thanks', 'Tim Editorial ULYAH', 'ebooks/kisah-luqman/en/kisah-luqman-01-hikmah-dan-syukur.pdf', 5, 'original', 'Ditulis berdasarkan QS. Luqman 12-12 (quran-json, CC-BY-4.0). Tidak ada kutipan pihak ketiga berhak cipta.');
INSERT INTO stories (title, slug, lang, series_key, episode_number, category_id, body, ai_generated, qc_status, source_format, status, confidence_score, related_ayah_id, pdf_ebook_id, published_at)
SELECT 'Episode 1: Luqman Is Granted Wisdom and Commanded to Give Thanks', 'kisah-luqman-01-hikmah-dan-syukur', 'en', 'kisah-luqman', 1, 5, 'Luqman Al-Hakim was a righteous servant whose name Allah immortalized as the title of a surah in the Qur''an. Allah granted him "hikmah" — wisdom, sound understanding, and precision in word and deed. Allah said, "And We had certainly given Luqman wisdom [and said], ''Be grateful to Allah.'' And whoever is grateful is grateful for [the benefit of] himself. And whoever denies [His favor] — then indeed, Allah is Free of need and Praiseworthy" (Qur''an 31:12).

Notice that the first core of the wisdom Allah mentions is the command to give thanks. This shows that the height of wisdom is not skill in debate, but the awareness to recognize Allah''s blessings and be grateful for them. The wise person is the one who knows how to thank the Giver of blessings.

The verse also teaches that the benefit of gratitude returns to the one who does it: "grateful for [the benefit of] himself." Allah does not need a servant''s thanks; He is the Free of need, the Praiseworthy. It is gratitude that increases blessing, while ingratitude only harms oneself.

Reflection: true wisdom begins with a grateful heart. Before Luqman advised his son on many things, Allah first taught that the foundation of all good is to know and thank the Giver.

Source & Note: evidence from the Qur''an, 31:12 (text & translation from the quran-json dataset). The majority of scholars hold that Luqman was a wise, righteous servant, not a prophet. Accounts of his origins (some reports say he was from Abyssinia/Nubia) come from tradition/tafsir and are not certain; what is firm from the ayah is that he was given wisdom.', 0, 'qc_pending', 'ai_original', 'published', 1.0,
  (SELECT id FROM ayah WHERE surah_id = 31 AND number = 12), 401, datetime('now');

INSERT INTO ebooks (id, title, author, r2_key, category_id, license_status, license_note) VALUES (402, 'Episode 2: Wasiat Terbesar — Jangan Menyekutukan Allah', 'Tim Editorial ULYAH', 'ebooks/kisah-luqman/id/kisah-luqman-02-jangan-syirik-dan-bakti-orang-tua.pdf', 5, 'original', 'Ditulis berdasarkan QS. Luqman 13-15 (quran-json, CC-BY-4.0). Tidak ada kutipan pihak ketiga berhak cipta.');
INSERT INTO stories (title, slug, lang, series_key, episode_number, category_id, body, ai_generated, qc_status, source_format, status, confidence_score, related_ayah_id, pdf_ebook_id, published_at)
SELECT 'Episode 2: Wasiat Terbesar — Jangan Menyekutukan Allah', 'kisah-luqman-02-jangan-syirik-dan-bakti-orang-tua', 'id', 'kisah-luqman', 2, 5, 'Nasihat pertama dan terpenting yang Luqman sampaikan kepada anaknya adalah menjaga tauhid dan menjauhi syirik. Allah berfirman, "Dan (ingatlah) ketika Luqman berkata kepada anaknya, ketika dia memberi pelajaran kepadanya, ‘Wahai anakku! Janganlah engkau menyekutukan Allah, sesungguhnya menyekutukan (Allah) adalah benar-benar kezaliman yang besar’" (QS. Luqman: 13).

Luqman menyebut syirik sebagai "kezaliman yang besar" (zulmun ''azhim) — karena syirik menempatkan sesuatu bukan pada tempatnya: memberikan hak ibadah, yang hanya milik Allah, kepada selain-Nya. Inilah pondasi yang ia tanamkan lebih dulu, sebab tanpa tauhid, seluruh amal kebaikan kehilangan maknanya.

Di sela nasihat Luqman, Allah menyisipkan perintah berbakti kepada orang tua, sekaligus batasannya, "Dan Kami perintahkan kepada manusia (agar berbuat baik) kepada kedua orang tuanya… Bersyukurlah kepada-Ku dan kepada kedua orang tuamu. Hanya kepada Aku kembalimu. Tetapi jika keduanya memaksamu untuk mempersekutukan Aku dengan sesuatu yang engkau tidak mempunyai ilmu tentang itu, maka janganlah engkau menaati keduanya, dan pergaulilah keduanya di dunia dengan baik…" (QS. Luqman: 14-15).

Hikmah: mendidik anak dimulai dari menanamkan tauhid yang murni. Berbakti kepada orang tua adalah kewajiban agung, namun ketaatan kepada makhluk tidak boleh melanggar ketaatan kepada Allah — sebuah keseimbangan yang diajarkan langsung dalam untaian ayat ini.

Sumber & Catatan: dalil dari Al-Qur''an, QS. Luqman: 13-15. Ayat 14-15 adalah sisipan firman Allah di tengah wasiat Luqman (menegaskan bakti kepada orang tua dengan batas tidak menaati dalam kesyirikan), lalu ayat 16 kembali kepada perkataan Luqman.', 0, 'qc_pending', 'ai_original', 'published', 1.0,
  (SELECT id FROM ayah WHERE surah_id = 31 AND number = 13), 402, datetime('now');
INSERT INTO ebooks (id, title, author, r2_key, category_id, license_status, license_note) VALUES (403, 'Episode 2: The Greatest Counsel — Do Not Associate Partners with Allah', 'Tim Editorial ULYAH', 'ebooks/kisah-luqman/en/kisah-luqman-02-jangan-syirik-dan-bakti-orang-tua.pdf', 5, 'original', 'Ditulis berdasarkan QS. Luqman 13-15 (quran-json, CC-BY-4.0). Tidak ada kutipan pihak ketiga berhak cipta.');
INSERT INTO stories (title, slug, lang, series_key, episode_number, category_id, body, ai_generated, qc_status, source_format, status, confidence_score, related_ayah_id, pdf_ebook_id, published_at)
SELECT 'Episode 2: The Greatest Counsel — Do Not Associate Partners with Allah', 'kisah-luqman-02-jangan-syirik-dan-bakti-orang-tua', 'en', 'kisah-luqman', 2, 5, 'The first and most important advice Luqman gave his son was to guard tawhid and shun shirk. Allah said, "And [mention] when Luqman said to his son while he was instructing him, ''O my son, do not associate [anything] with Allah. Indeed, association [with Him] is great injustice''" (Qur''an 31:13).

Luqman called shirk "great injustice" (zulmun ''azhim) — because shirk puts a thing out of its rightful place: giving the right of worship, which belongs to Allah alone, to another. This is the foundation he planted first, for without tawhid, all good deeds lose their meaning.

In the midst of Luqman''s counsel, Allah inserts the command to be dutiful to parents, along with its limit: "And We have enjoined upon man [care] for his parents… Be grateful to Me and to your parents; to Me is the [final] destination. But if they endeavor to make you associate with Me that of which you have no knowledge, do not obey them but accompany them in [this] world with kindness…" (Qur''an 31:14-15).

Reflection: raising a child begins with planting pure tawhid. Dutifulness to parents is a mighty obligation, yet obedience to creation must not violate obedience to Allah — a balance taught directly within this string of verses.

Source & Note: evidence from the Qur''an, 31:13-15. Verses 14-15 are Allah''s insertion within Luqman''s counsel (affirming kindness to parents with the limit of not obeying them in shirk), then verse 16 returns to Luqman''s own words.', 0, 'qc_pending', 'ai_original', 'published', 1.0,
  (SELECT id FROM ayah WHERE surah_id = 31 AND number = 13), 403, datetime('now');

INSERT INTO ebooks (id, title, author, r2_key, category_id, license_status, license_note) VALUES (404, 'Episode 3: Kesadaran bahwa Allah Melihat Sekecil Apa Pun', 'Tim Editorial ULYAH', 'ebooks/kisah-luqman/id/kisah-luqman-03-muraqabah-sekecil-biji-sawi.pdf', 5, 'original', 'Ditulis berdasarkan QS. Luqman 16-16 (quran-json, CC-BY-4.0). Tidak ada kutipan pihak ketiga berhak cipta.');
INSERT INTO stories (title, slug, lang, series_key, episode_number, category_id, body, ai_generated, qc_status, source_format, status, confidence_score, related_ayah_id, pdf_ebook_id, published_at)
SELECT 'Episode 3: Kesadaran bahwa Allah Melihat Sekecil Apa Pun', 'kisah-luqman-03-muraqabah-sekecil-biji-sawi', 'id', 'kisah-luqman', 3, 5, 'Luqman menanamkan ke dalam hati anaknya kesadaran bahwa tidak ada satu pun perbuatan yang luput dari pengetahuan Allah — sekecil apa pun dan di mana pun ia berada. Allah berfirman, "(Luqman berkata), ‘Wahai anakku! Sungguh, jika ada (sesuatu perbuatan) seberat biji sawi, dan berada dalam batu atau di langit atau di bumi, niscaya Allah akan menghadirkannya (untuk memberi balasan). Sesungguhnya Allah Mahahalus, Mahateliti’" (QS. Luqman: 16).

Biji sawi adalah perumpamaan untuk sesuatu yang amat kecil. Luqman mengajarkan bahwa amal sekecil itu pun, meski tersembunyi di dalam batu, di langit yang jauh, atau di kedalaman bumi, tetap tercatat dan akan Allah hadirkan pada hari perhitungan. Allah "Mahahalus" (Lathif) — mengetahui yang paling tersembunyi, dan "Mahateliti" (Khabir) — tak ada yang luput dari-Nya.

Kesadaran ini disebut muraqabah: merasa selalu diawasi Allah. Inilah pendidikan hati yang paling ampuh — anak yang tumbuh dengan keyakinan bahwa Allah melihat segala sesuatu akan terjaga dari keburukan meski tak ada seorang pun yang mengawasinya.

Hikmah: pengawasan terbaik bukan datang dari manusia, melainkan dari kesadaran bahwa Allah senantiasa melihat. Menanamkan muraqabah pada anak lebih kuat daripada sekadar larangan, karena ia menjaga diri dari dalam.

Sumber & Catatan: dalil dari Al-Qur''an, QS. Luqman: 16. Perumpamaan "biji sawi" (habbah min khardal) adalah nas Al-Qur''an untuk menggambarkan sekecil-kecilnya amal yang tetap diperhitungkan.', 0, 'qc_pending', 'ai_original', 'published', 1.0,
  (SELECT id FROM ayah WHERE surah_id = 31 AND number = 16), 404, datetime('now');
INSERT INTO ebooks (id, title, author, r2_key, category_id, license_status, license_note) VALUES (405, 'Episode 3: Awareness That Allah Sees the Smallest Thing', 'Tim Editorial ULYAH', 'ebooks/kisah-luqman/en/kisah-luqman-03-muraqabah-sekecil-biji-sawi.pdf', 5, 'original', 'Ditulis berdasarkan QS. Luqman 16-16 (quran-json, CC-BY-4.0). Tidak ada kutipan pihak ketiga berhak cipta.');
INSERT INTO stories (title, slug, lang, series_key, episode_number, category_id, body, ai_generated, qc_status, source_format, status, confidence_score, related_ayah_id, pdf_ebook_id, published_at)
SELECT 'Episode 3: Awareness That Allah Sees the Smallest Thing', 'kisah-luqman-03-muraqabah-sekecil-biji-sawi', 'en', 'kisah-luqman', 3, 5, 'Luqman planted in his son''s heart the awareness that no deed escapes Allah''s knowledge — however small, and wherever it may be. Allah said, "[Luqman said], ''O my son, indeed if wrong should be the weight of a mustard seed and should be within a rock or [anywhere] in the heavens or in the earth, Allah will bring it forth. Indeed, Allah is Subtle and Acquainted''" (Qur''an 31:16).

The mustard seed is a likeness for something extremely small. Luqman taught that even a deed that tiny, though hidden inside a rock, in the far heavens, or in the depths of the earth, is still recorded and will be brought forth by Allah on the Day of Reckoning. Allah is "Subtle" (Latif) — knowing the most hidden things — and "Acquainted" (Khabir) — nothing escapes Him.

This awareness is called muraqabah: to feel always watched by Allah. This is the most powerful education of the heart — a child who grows up certain that Allah sees everything will be guarded from evil even when no one is watching.

Reflection: the best watchfulness comes not from people, but from the awareness that Allah is ever-seeing. Instilling muraqabah in a child is stronger than mere prohibition, because it guards a person from within.

Source & Note: evidence from the Qur''an, 31:16. The likeness of the "mustard seed" (habbah min khardal) is the Qur''an''s own text for depicting the smallest deed that is still brought to account.', 0, 'qc_pending', 'ai_original', 'published', 1.0,
  (SELECT id FROM ayah WHERE surah_id = 31 AND number = 16), 405, datetime('now');

INSERT INTO ebooks (id, title, author, r2_key, category_id, license_status, license_note) VALUES (406, 'Episode 4: Salat, Amar Ma''ruf Nahi Munkar, dan Kesabaran', 'Tim Editorial ULYAH', 'ebooks/kisah-luqman/id/kisah-luqman-04-shalat-amar-maruf-dan-sabar.pdf', 5, 'original', 'Ditulis berdasarkan QS. Luqman 17-17 (quran-json, CC-BY-4.0). Tidak ada kutipan pihak ketiga berhak cipta.');
INSERT INTO stories (title, slug, lang, series_key, episode_number, category_id, body, ai_generated, qc_status, source_format, status, confidence_score, related_ayah_id, pdf_ebook_id, published_at)
SELECT 'Episode 4: Salat, Amar Ma''ruf Nahi Munkar, dan Kesabaran', 'kisah-luqman-04-shalat-amar-maruf-dan-sabar', 'id', 'kisah-luqman', 4, 5, 'Setelah menanamkan tauhid dan muraqabah, Luqman membimbing anaknya kepada amal nyata: menegakkan salat, berdakwah kepada kebaikan, dan bersabar. Allah berfirman, "(Luqman berkata), ‘Wahai anakku! Laksanakanlah salat dan suruhlah (manusia) berbuat yang makruf dan cegahlah (mereka) dari yang mungkar, dan bersabarlah terhadap apa yang menimpamu. Sesungguhnya yang demikian itu termasuk perkara yang penting (diutamakan)’" (QS. Luqman: 17).

Urutannya sangat rapi dan penuh hikmah. Ia memulai dengan salat — hubungan langsung antara hamba dan Tuhannya, tiang agama. Lalu amar makruf dan nahi mungkar — kepedulian terhadap masyarakat, agar kebaikan tersebar dan keburukan tercegah. Dan karena orang yang menyeru kebaikan pasti menghadapi tantangan, Luqman menutupnya dengan perintah bersabar.

Luqman menyebut ketiganya sebagai "termasuk perkara yang diutamakan" (min ''azmil umur) — perkara yang menuntut keteguhan tekad. Ini menunjukkan bahwa iman tidak berhenti pada keyakinan hati, melainkan mewujud dalam ibadah, kepedulian sosial, dan ketabahan.

Hikmah: pendidikan yang sempurna memadukan hubungan dengan Allah (salat), hubungan dengan sesama (amar makruf nahi mungkar), dan kekuatan jiwa (sabar). Ketiganya adalah bekal utama seorang mukmin dalam mengarungi kehidupan.

Sumber & Catatan: dalil dari Al-Qur''an, QS. Luqman: 17. Ungkapan "min ''azmil umur" (termasuk perkara yang memerlukan keteguhan tekad) adalah nas ayat yang menegaskan tingginya kedudukan ketiga amalan tersebut.', 0, 'qc_pending', 'ai_original', 'published', 1.0,
  (SELECT id FROM ayah WHERE surah_id = 31 AND number = 17), 406, datetime('now');
INSERT INTO ebooks (id, title, author, r2_key, category_id, license_status, license_note) VALUES (407, 'Episode 4: Prayer, Enjoining Good, and Patience', 'Tim Editorial ULYAH', 'ebooks/kisah-luqman/en/kisah-luqman-04-shalat-amar-maruf-dan-sabar.pdf', 5, 'original', 'Ditulis berdasarkan QS. Luqman 17-17 (quran-json, CC-BY-4.0). Tidak ada kutipan pihak ketiga berhak cipta.');
INSERT INTO stories (title, slug, lang, series_key, episode_number, category_id, body, ai_generated, qc_status, source_format, status, confidence_score, related_ayah_id, pdf_ebook_id, published_at)
SELECT 'Episode 4: Prayer, Enjoining Good, and Patience', 'kisah-luqman-04-shalat-amar-maruf-dan-sabar', 'en', 'kisah-luqman', 4, 5, 'After planting tawhid and muraqabah, Luqman guided his son to concrete deeds: establishing prayer, calling to good, and being patient. Allah said, "[Luqman said], ''O my son, establish prayer, enjoin what is right, forbid what is wrong, and be patient over what befalls you. Indeed, [all] that is of the matters [requiring] determination''" (Qur''an 31:17).

The order is orderly and full of wisdom. He begins with prayer — the direct link between a servant and his Lord, the pillar of the religion. Then enjoining good and forbidding evil — care for society, so that good spreads and evil is checked. And because one who calls to good will surely face challenges, Luqman closes with the command to be patient.

Luqman calls all three "of the matters [requiring] determination" (min ''azm al-umur) — matters that demand firm resolve. This shows that faith does not stop at the heart''s conviction, but takes form in worship, social concern, and steadfastness.

Reflection: complete education combines the relationship with Allah (prayer), the relationship with people (enjoining good and forbidding evil), and strength of soul (patience). These three are a believer''s chief provision in navigating life.

Source & Note: evidence from the Qur''an, 31:17. The phrase "min ''azm al-umur" (among the matters requiring firm resolve) is the verse''s own text affirming the high standing of these three deeds.', 0, 'qc_pending', 'ai_original', 'published', 1.0,
  (SELECT id FROM ayah WHERE surah_id = 31 AND number = 17), 407, datetime('now');

INSERT INTO ebooks (id, title, author, r2_key, category_id, license_status, license_note) VALUES (408, 'Episode 5: Adab, Kerendahan Hati, dan Kesederhanaan', 'Tim Editorial ULYAH', 'ebooks/kisah-luqman/id/kisah-luqman-05-adab-dan-kesederhanaan.pdf', 5, 'original', 'Ditulis berdasarkan QS. Luqman 18-19 (quran-json, CC-BY-4.0). Tidak ada kutipan pihak ketiga berhak cipta.');
INSERT INTO stories (title, slug, lang, series_key, episode_number, category_id, body, ai_generated, qc_status, source_format, status, confidence_score, related_ayah_id, pdf_ebook_id, published_at)
SELECT 'Episode 5: Adab, Kerendahan Hati, dan Kesederhanaan', 'kisah-luqman-05-adab-dan-kesederhanaan', 'id', 'kisah-luqman', 5, 5, 'Luqman menutup rangkaian nasihatnya dengan pendidikan akhlak dan adab bergaul — bagaimana seorang mukmin bersikap terhadap sesama, jauh dari kesombongan. Allah berfirman, "(Luqman berkata), ‘Dan janganlah kamu memalingkan wajah dari manusia (karena sombong) dan janganlah berjalan di bumi dengan angkuh. Sungguh, Allah tidak menyukai orang-orang yang sombong dan membanggakan diri. Dan sederhanakanlah dalam berjalan dan lunakkanlah suaramu. Sesungguhnya seburuk-buruk suara ialah suara keledai’" (QS. Luqman: 18-19).

Ayat ini melarang tiga bentuk kesombongan sekaligus: memalingkan wajah dari orang lain karena merasa lebih tinggi, berjalan dengan angkuh, dan mengeraskan suara secara berlebihan. Sebagai gantinya, Luqman mengajarkan kesederhanaan: berjalan dengan wajar dan berbicara dengan suara yang lembut.

Perumpamaan "suara keledai" adalah teguran halus namun tegas terhadap orang yang gemar meninggikan suara tanpa keperluan. Akhlak yang baik, menurut Luqman, tercermin bahkan dalam cara berjalan dan berbicara — hal-hal kecil yang justru menunjukkan kerendahan hati sejati.

Hikmah: ilmu dan iman harus berbuah adab. Luqman menyempurnakan nasihatnya dengan akhlak, karena kebijaksanaan tanpa kerendahan hati adalah kesombongan, dan Allah tidak menyukai orang yang sombong lagi membanggakan diri.

Sumber & Catatan: dalil dari Al-Qur''an, QS. Luqman: 18-19. Seluruh rangkaian kisah ini (ayat 12-19) adalah nas Al-Qur''an; tidak ada tambahan riwayat di luar teks. Sekali lagi, jumhur ulama memandang Luqman sebagai hamba saleh yang bijak, bukan nabi — sehingga kisahnya ditempatkan dalam kategori Kisah Islami, bukan Kisah Para Nabi.', 0, 'qc_pending', 'ai_original', 'published', 1.0,
  (SELECT id FROM ayah WHERE surah_id = 31 AND number = 18), 408, datetime('now');
INSERT INTO ebooks (id, title, author, r2_key, category_id, license_status, license_note) VALUES (409, 'Episode 5: Manners, Humility, and Moderation', 'Tim Editorial ULYAH', 'ebooks/kisah-luqman/en/kisah-luqman-05-adab-dan-kesederhanaan.pdf', 5, 'original', 'Ditulis berdasarkan QS. Luqman 18-19 (quran-json, CC-BY-4.0). Tidak ada kutipan pihak ketiga berhak cipta.');
INSERT INTO stories (title, slug, lang, series_key, episode_number, category_id, body, ai_generated, qc_status, source_format, status, confidence_score, related_ayah_id, pdf_ebook_id, published_at)
SELECT 'Episode 5: Manners, Humility, and Moderation', 'kisah-luqman-05-adab-dan-kesederhanaan', 'en', 'kisah-luqman', 5, 5, 'Luqman closed his string of counsel with the education of character and the manners of dealing with others — how a believer behaves toward people, far from arrogance. Allah said, "[Luqman said], ''And do not turn your cheek [in contempt] toward people and do not walk through the earth exultantly. Indeed, Allah does not like everyone self-deluded and boastful. And be moderate in your pace and lower your voice; indeed, the most disagreeable of sounds is the voice of donkeys''" (Qur''an 31:18-19).

This verse forbids three forms of arrogance at once: turning one''s face from others out of feeling superior, walking haughtily, and raising the voice excessively. In their place, Luqman teaches moderation: walking naturally and speaking in a gentle voice.

The likeness of the "voice of donkeys" is a subtle yet firm rebuke of those fond of raising their voices needlessly. Good character, according to Luqman, shows even in how one walks and speaks — small things that in fact reveal true humility.

Reflection: knowledge and faith must bear the fruit of good manners. Luqman perfects his counsel with character, because wisdom without humility is arrogance, and Allah does not like the one who is self-deluded and boastful.

Source & Note: evidence from the Qur''an, 31:18-19. This entire story (verses 12-19) is the Qur''an''s own text; there is no added report beyond it. Again, the majority of scholars regard Luqman as a wise, righteous servant, not a prophet — so his story is placed in the "Kisah Islami" category, not "Kisah Para Nabi."', 0, 'qc_pending', 'ai_original', 'published', 1.0,
  (SELECT id FROM ayah WHERE surah_id = 31 AND number = 18), 409, datetime('now');

